            jksadhflasjkd
          </el-dropdown-menu>
        </el-dropdown>
      </div> -->
    </div>

    <div class="swiper-container">
      <div class="swiper-wrapper">
        <div class="swiper-slide"><div class="wrapper"><SlideOne /></div></div>
        <div class="swiper-slide"><div class="wrapper"><SlideTwo /></div></div>
        <div class="swiper-slide"><div class="wrapper"><SlideThree /></div></div>
        <div class="swiper-slide"><div class="wrapper"><SlideFour /></div></div>
        <div class="swiper-slide"><div class="wrapper"><SlideFive /></div></div>
      </div>
    </div>

    <div class="footer">
      <el-button @click="swiper.slidePrev(500, null)" round>Prev</el-button>
      <el-switch
        v-model="darkMode"
        active-color="#000"
        inactive-color="#f2f2f2">
      </el-switch>
      <el-button @click="swiper.slideNext(500, null)" round>Next</el-button>
    </div>

  </div>
</template>

<script>
import Swiper from 'swiper';
import 'swiper/swiper-bundle.css';

import SlideOne from './components/slides/SlideOne';
import SlideTwo from './components/slides/SlideTwo';
import SlideThree from './components/slides/SlideThree';
import SlideFour from './components/slides/SlideFour';
import SlideFive from './components/slides/SlideFive'

export default {

  components: { SlideOne, SlideTwo, SlideThree, SlideFour, SlideFive },

  name: 'App',
  data() {
    return {
      swiper: null,
      darkMode: false
    }
  },
  mounted() {

    const mode = localStorage.getItem('darkMode');

    console.log('mode', mode)

    this.darkMode = mode === 'true' ? true : false;

    this.swiper = new Swiper('.swiper-container', {
      navigation: {
        nextEl: '#next-btn',
        prevEl: '#prev-btn',
      },
    });
  },

  watch: {
    darkMode(value) {
      localStorage.setItem('darkMode', value)
    }
  },

  computed: {
    appClasses () {
      return [
        { 'light-mode': !this.darkMode },
        { 'dark-mode': this.darkMode }
      ];
    }
  }
}
</script>

